<template>
  <div class="container">
    <div class="Portfolio">
      <div class="inner">
        <h3 class="title">{{ $t('my_works') }}</h3>
        <div class="itemsWrapper">
          <TransitionGroup name="list" tag="div">
            <div 
              class="item" 
              v-for="post in arrPosts" 
              :key="post.id"
            >
              <div class="container">
                <div class="inner">
                  <img :src="post.img" alt="img" class="image" />
                  <div class="info">
                    <h3 class="subtitle">{{ post.title }}</h3>
                    <div class="badgeList">
                      <span class="badge">{{ post.tags.year }}</span>
                      <span class="badge">{{ post.tags.techno1 }}</span>
                      <span class="badge">{{ post.tags.techno2 }}</span>
                      <span class="badge">{{ post.tags.techno3 }}</span>
                    </div>
                    <p v-if="$i18n.locale === 'en'" class="text">{{ post.text_en }}</p>
                    <p v-else class="text">{{ post.text_ru }}</p>
                    <div>
                      <a
                        :href="post.url"
                        target="_blank"
                        rel="noreferrer"
                        class="button"
                      >
                        {{ $t('go_to') }}
                      </a>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </TransitionGroup>
        </div>
        <button
          @click="showMore"
          class="loadMoreBtn"
          v-if="arrPosts.length < 22"
        >
          {{ $t('load_more') }}
        </button>
      </div>
    </div>
    <up-btn />
  </div>
</template>

<script>
import upBtn from '../components/upBtn.vue';

export default {
  components: { upBtn },
  data() {
    return {
      visiblePosts: 4,
      step: 4,
    };
  },
  computed: {
    arrPosts() {
      let postsList = this.$store.state.posts;
      let reversList = postsList.slice().reverse();
      return reversList.slice(0, this.visiblePosts);
    },
  },
  methods: {
    showMore() {
      this.visiblePosts = this.step + this.arrPosts.length;
    },
  },
};
</script>

<style lang="scss">
.list-enter-active,
.list-leave-active {
  transition: all 0.5s ease;
}

.list-enter-from,
.list-leave-to {
  opacity: 0;
  transform: translateX(30px);
}

.Portfolio {
  .inner {
    .title {
      text-align: center;
      font-size: 32px;
    }

    .itemsWrapper {
      display: flex;
      flex-direction: column;
    }

    .item {
      padding: 75px 0;

      @media (max-width: 425px) {
        padding: 35px 0;
      }

      &:not(:last-child) {
        border-bottom: 1px solid $lightGray;
      }

      .inner {
        display: flex;
        align-items: center;

        @media (max-width: 1024px) {
          flex-direction: column;
        }

        .image {
          cursor: pointer;
          transition: 0.3s;
          max-width: 100%;
          height: auto;

          &:hover {
            transform: scale(1.1);
            transition: 0.3s;
          }
        }

        .info {
          margin-left: 115px;

          @media (max-width: 1024px) {
            margin-left: 0;
            text-align: center;
          }

          .subtitle {
            font-size: 24px;
            font-weight: 800;
            letter-spacing: 0.15em;

            @media (max-width: 1024px) {
              margin-top: 40px;
              letter-spacing: 0;
              margin-bottom: 5px;
            }
          }

          .badgeList {
            .badge {
              display: inline-block;
              background: $white;
              border: 1px solid $blue;
              padding: 2px 10px;
              font-size: 12px;
              font-weight: 700;
              line-height: 1;
              border-radius: 50px;
              text-align: center;
              transition: 0.5s;
              cursor: default;
              color: $blue;
              white-space: nowrap;
              vertical-align: baseline;

              &:not(:last-child) {
                margin-right: 5px;
              }

              &:hover {
                background: $blue;
                color: $white;
                transition: 0.5s;
              }
            }
          }

          .text {
            max-width: 460px;
            width: 100%;
            color: $gray;
            margin: 15px 0 25px;

            @media (max-width: 1024px) {
              max-width: unset;
            }
          }

          .button {
            display: inline-block;
            padding: 10px 25px;
            background: $white;
            font-size: 14px;
            border-radius: 12px;
            min-width: 180px;
            text-align: center;
            border: 1px solid $blue;
            color: $blue;
            transition: 0.2s ease-in-out;
            text-decoration: none;

            &:hover {
              background: $blue;
              color: $white;
              text-decoration: none;
            }
          }
        }
      }
    }

    .loadMoreBtn {
      display: block;
      margin: 0 auto;
      padding: 10px 25px;
      background: $blue;
      font-size: 14px;
      border-radius: 12px;
      min-width: 180px;
      text-align: center;
      border: 1px solid $white;
      color: $white;
      transition: 0.2s ease-in-out;
      text-decoration: none;
      cursor: pointer;
      outline: none;
      margin-bottom: 50px;

      &:hover {
        background: $nila-blue;
      }
    }
  }
}
</style>